<?php
require_once '../includes/config.php';
$slug=$_GET['e'] ?? '';
$stmt=db()->prepare('SELECT s.*, b.name breeder_name FROM site_settings s JOIN breeder b ON b.id=s.breeder_id WHERE s.public_slug=:slug');$stmt->execute(['slug'=>$slug]);$s=$stmt->fetch();
if(!$s){http_response_code(404);exit('Site introuvable.');}
$dogs=db()->prepare('SELECT * FROM dogs WHERE breeder_id=:bid AND status=:status ORDER BY name');$dogs->execute(['bid'=>$s['breeder_id'],'status'=>'actif']);
$puppies=db()->prepare("SELECT * FROM puppies WHERE breeder_id=:bid AND COALESCE(is_sold,false)=false ORDER BY created_at DESC");$puppies->execute(['bid'=>$s['breeder_id']]);
?><!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?= e($s['breeder_name']) ?></title><style>body{margin:0;background:#101114;color:#f4efe7;font-family:Inter,Arial,sans-serif}.hero{padding:80px 8vw;background:linear-gradient(135deg,#08090b,#1d1f26)}.eyebrow{color:<?= e($s['accent_color']) ?>;letter-spacing:.18em;text-transform:uppercase}.title{font-family:Georgia,serif;font-size:52px}.section{padding:42px 8vw}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:18px}.card{border:1px solid #333842;background:#17191f;border-radius:22px;padding:22px}.muted{color:#aaa}a{color:<?= e($s['accent_color']) ?>}</style></head><body><header class="hero"><p class="eyebrow"><?= e($s['breeder_name']) ?></p><h1 class="title"><?= e($s['headline']) ?></h1><p><?= nl2br(e($s['description'])) ?></p><p class="muted"><?= e($s['city']) ?> · <?= e($s['phone']) ?> · <a href="mailto:<?= e($s['email']) ?>"><?= e($s['email']) ?></a></p></header><section class="section"><h2>Nos chiens</h2><div class="grid"><?php foreach($dogs as $d): ?><article class="card"><h3><?= e($d['name']) ?></h3><p class="muted"><?= e($d['breed']) ?> · <?= e($d['sex']) ?></p><p><?= nl2br(e($d['notes'])) ?></p></article><?php endforeach; ?></div></section><section class="section"><h2>Chiots disponibles</h2><div class="grid"><?php foreach($puppies as $p): ?><article class="card"><h3><?= e($p['name'] ?: 'Chiot disponible') ?></h3><p class="muted"><?= e($p['sex']) ?> · <?= e($p['color']) ?> · <?= e($p['status']) ?></p><p><?= e($p['sale_price']) ?> €</p></article><?php endforeach; ?></div></section></body></html>
